INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('aboriginal-6f0ba476-moex-00240', 'aboriginal-6f0ba476', 'aboriginal-6f0ba476-moex-112-e0b1f2ed', 'sub-aboriginal-6f0ba476-01', NULL, 'single_choice', '甲公司於X5年以每台$100,000出售3,000台某類型之機器手臂，附有1年的產品保固，依據以 往的經驗，大約有85%的機器手臂不會發生任何損壞，10%會發生每台修理費用$5,000之小瑕疵， 5%會發生每台修理費用$20,000之大瑕疵。若甲公司X5年度實際發生維修支出$1,100,000，請問 X5年底「產品保證負債準備」之餘額應為何？', '["$1,100,000", "$3,400,000", "$4,500,000", "$5,600,000"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:54+00:00", "source_pdf_sha1": "364397ce3438", "answer_pdf_sha1": "cf1b50b9dbf8", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "508", "s": "1303", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 20, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('aboriginal-6f0ba476-moex-00241', 'aboriginal-6f0ba476', 'aboriginal-6f0ba476-moex-112-e0b1f2ed', 'sub-aboriginal-6f0ba476-01', NULL, 'single_choice', '若公司為實行員工認股計畫買回公司流通在外股票（庫藏股交易），則在編製現金流量表時，此項 交易應列為那一種活動？', '["營業活動", "投資活動", "籌資活動", "不須列在現金流量表上"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:54+00:00", "source_pdf_sha1": "364397ce3438", "answer_pdf_sha1": "cf1b50b9dbf8", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "508", "s": "1303", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 21, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('aboriginal-6f0ba476-moex-00242', 'aboriginal-6f0ba476', 'aboriginal-6f0ba476-moex-112-e0b1f2ed', 'sub-aboriginal-6f0ba476-01', NULL, 'single_choice', '甲公司2022年度資料：折舊費用$70,000，應付帳款減少$28,000，專利權攤銷費用$86,000，出售 土地利得$800,000，償還公司債$600,000，向銀行融資$4,000,000，購買設備$960,000，本期淨利 $5,000,000，則間接法所算出之營業活動淨現金流入為：', '["$4,384,000", "$4,328,000", "$4,242,000", "$5,616,000"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:54+00:00", "source_pdf_sha1": "364397ce3438", "answer_pdf_sha1": "cf1b50b9dbf8", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "508", "s": "1303", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 22, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('aboriginal-6f0ba476-moex-00243', 'aboriginal-6f0ba476', 'aboriginal-6f0ba476-moex-112-e0b1f2ed', 'sub-aboriginal-6f0ba476-01', NULL, 'single_choice', '甲公司2022年度本期淨利$14,000,000，其中含折舊費用$1,750,000，出售機器設備損失$3,192,000， 土地出售利益$2,660,000，另外已知當年度存貨金額有變動。甲公司2022年度現金流量表（以間 接法編製）營業活動之淨現金流量為$16,786,000。試問存貨當年度變動金額為何？', '["減少$1,568,000", "增加$1,568,000", "減少$504,000", "增加$504,000"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:54+00:00", "source_pdf_sha1": "364397ce3438", "answer_pdf_sha1": "cf1b50b9dbf8", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "508", "s": "1303", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 23, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('aboriginal-6f0ba476-moex-00244', 'aboriginal-6f0ba476', 'aboriginal-6f0ba476-moex-112-e0b1f2ed', 'sub-aboriginal-6f0ba476-01', NULL, 'single_choice', '甲公司2022年1月1日資產總額為$1,000,000，負債比率為34%，股東權益資料如下：包括每股 面額$100，股利率6.5%之特別股4,000股、每股面額$10的普通股，保留盈餘$60,000。2022年之 銷貨收入$244,000，銷貨退回與折讓$6,000，銷貨成本$50,000，營業外收入$12,000，營業費用 $10,000，利息費用$8,000。若甲公司適用稅率為20%，當年度7月1日曾發放普通股15%股票股 利，年底普通股每股市價為$69.5（每股盈餘及本益比的計算採四捨五入至小數第二位）。下列敘 述何者正確？', '["2022年度之毛利率低於60%", "2022年底流通在外股數21,500股", "2022年底普通股之本益比12.5", "2022年底每股盈餘$5.2"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:54+00:00", "source_pdf_sha1": "364397ce3438", "answer_pdf_sha1": "cf1b50b9dbf8", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "508", "s": "1303", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 24, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('aboriginal-6f0ba476-moex-00245', 'aboriginal-6f0ba476', 'aboriginal-6f0ba476-moex-112-e0b1f2ed', 'sub-aboriginal-6f0ba476-01', NULL, 'single_choice', '甲公司2022年6月面臨一法律訴訟，訴訟結果將於1年內確定，經公司法務人員與律師估計， 勝訴不用賠的機率為 25%，但 75%機率可能會敗訴需賠$9,000,000，試問該負債準備之最佳估計 金額為何？（假設該公司之前從未發生類似的訴訟案件）', '["$9,000,000", "$6,750,000", "$0", "$2,250,000"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:54+00:00", "source_pdf_sha1": "364397ce3438", "answer_pdf_sha1": "cf1b50b9dbf8", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "508", "s": "1303", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 25, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('aboriginal-6f0ba476-moex-00246', 'aboriginal-6f0ba476', 'aboriginal-6f0ba476-moex-112-9b7ab1bb', 'sub-aboriginal-6f0ba476-02', NULL, 'essay', '甲、乙、丙三人合夥共同出資經營 A咖啡店，聘僱丁為店長，甲、乙、
丙均得以老闆之身分指揮監督丁。某日，丁在客人戊到 A咖啡店消費時，
利用為其準備飲料之機會，將安眠藥加入戊點用之飲品，丁並俟戊喝下
藥效發作後，再將戊扶至店外後方以預藏之水果刀殺害。今戊之母庚訴
請甲、乙、丙與丁連帶賠償其所支出之殯葬費、戊對庚之扶養費，以及
庚之精神慰撫金，是否有理？（15 分）若戊生前將其 B房地贈與辛，業
經辛允受，則於戊遭殺害後，其唯一繼承人壬對辛撤銷該贈與契約，是
否有理？（10 分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:54+00:00", "source_pdf_sha1": "24a86a5609a7", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "508", "s": "0801", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "民法", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": "一", "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('aboriginal-6f0ba476-moex-00247', 'aboriginal-6f0ba476', 'aboriginal-6f0ba476-moex-112-9b7ab1bb', 'sub-aboriginal-6f0ba476-02', NULL, 'essay', '甲乙等數人分別共有 A地，甲經其他共有人全體同意，在該地上興建 B
屋。乙嗣將其 A地之應有部分讓售予丙，已辦畢登記。丙隨即聲請法院
裁判分割 A地，法院判決確定該地應予變價分割，其後由丁拍定買受，
取得 A 地所有權全部。今丁向法院訴請甲拆除 B 屋及將該部分土地騰
空返還予自己，並訴請甲給付相當於租金之不當得利。對此，甲抗辯 B
屋乃基於地上權或租賃關係而座落在丁之 A地上，係屬有權占有且有法
律上原因。問丁之請求是否有理？（25 分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:54+00:00", "source_pdf_sha1": "24a86a5609a7", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "508", "s": "0801", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "民法", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": "二", "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('aboriginal-6f0ba476-moex-00248', 'aboriginal-6f0ba476', 'aboriginal-6f0ba476-moex-112-9b7ab1bb', 'sub-aboriginal-6f0ba476-02', NULL, 'single_choice', '甲向乙借款新臺幣100萬元，經過10年，甲向乙承認該筆借款存在。該承認之性質為何？', '["意思表示", "意思通知", "觀念通知", "感情表示"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:54+00:00", "source_pdf_sha1": "24a86a5609a7", "answer_pdf_sha1": "239ddc873623", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "508", "s": "0801", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 1, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('aboriginal-6f0ba476-moex-00249', 'aboriginal-6f0ba476', 'aboriginal-6f0ba476-moex-112-9b7ab1bb', 'sub-aboriginal-6f0ba476-02', NULL, 'single_choice', '公同共有人依分產協議，而行使關於其分得所有權之移轉請求權時，該請求權之消滅時效期間為 幾年？', '["15年", "10年", "5年", "2年"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:54+00:00", "source_pdf_sha1": "24a86a5609a7", "answer_pdf_sha1": "239ddc873623", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "508", "s": "0801", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 2, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "財稅行政"}'::jsonb, NULL)
